const amqplib = require('amqplib');

const RABBITMQ_URL = process.env.RABBITMQ_URL || 'amqp://localhost';
const QUEUE_NAME = process.env.QUEUE_NAME || 'payment_events';

async function processPaymentEvent(event) {
  if (!event || typeof event !== 'object') {
    throw new Error('Invalid event payload');
  }

  const { paymentId, amount, currency, customerId, action } = event;

  if (!paymentId) throw new Error('Missing paymentId');
  if (typeof amount !== 'number' || Number.isNaN(amount)) throw new Error('Invalid amount');
  if (!currency) throw new Error('Missing currency');
  if (!customerId) throw new Error('Missing customerId');
  if (!action) throw new Error('Missing action');

  switch (action) {
    case 'charge':
      await chargeCustomer({ paymentId, amount, currency, customerId });
      break;
    case 'refund':
      await refundCustomer({ paymentId, amount, currency, customerId });
      break;
    case 'capture':
      await capturePayment({ paymentId, amount, currency, customerId });
      break;
    default:
      throw new Error(`Unsupported action: ${action}`);
  }
}

async function chargeCustomer({ paymentId, amount, currency, customerId }) {
  console.log(`Charging customer ${customerId} for ${amount} ${currency} (paymentId=${paymentId})`);
}

async function refundCustomer({ paymentId, amount, currency, customerId }) {
  console.log(`Refunding customer ${customerId} for ${amount} ${currency} (paymentId=${paymentId})`);
}

async function capturePayment({ paymentId, amount, currency, customerId }) {
  console.log(`Capturing payment ${paymentId} for customer ${customerId} in ${amount} ${currency}`);
}

async function startConsumer() {
  const connection = await amqplib.connect(RABBITMQ_URL);
  const channel = await connection.createChannel();

  await channel.assertQueue(QUEUE_NAME, { durable: true });
  channel.prefetch(10);

  console.log(`Waiting for messages in ${QUEUE_NAME}`);

  channel.consume(
    QUEUE_NAME,
    async (msg) => {
      if (!msg) return;

      try {
        const content = msg.content.toString('utf8');
        const event = JSON.parse(content);

        await processPaymentEvent(event);

        channel.ack(msg);
      } catch (err) {
        console.error('Failed to process payment event:', err.message);
        channel.nack(msg, false, false);
      }
    },
    { noAck: false }
  );

  const shutdown = async () => {
    try {
      await channel.close();
      await connection.close();
      process.exit(0);
    } catch (err) {
      process.exit(1);
    }
  };

  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);
}

startConsumer().catch((err) => {
  console.error('Consumer startup failed:', err);
  process.exit(1);
});